patch:
--- a/priority_encoder.v
+++ b/priority_encoder.v
@@ -1,6 +1,6 @@
 module priority_encoder_16bit(
   input [15:0] request,
   output reg [3:0] priority,
   output reg valid
 );
-  always @(request) begin
+  always @(*) begin
     if (request[15]) begin
       priority = 4'hF;
       valid = 1'b1;

before_code:
module priority_encoder_16bit(
  input [15:0] request,
  output reg [3:0] priority,
  output reg valid
);
  always @(request) begin
    if (request[15]) begin
      priority = 4'hF;
      valid = 1'b1;
    end else if (request[14]) begin
      priority = 4'hE;
      valid = 1'b1;
    end else if (request[0]) begin
      priority = 4'h0;
      valid = 1'b1;
    end else begin
      valid = 1'b0;
    end
  end
endmodule

after_code:
module priority_encoder_16bit(
  input [15:0] request,
  output reg [3:0] priority,
  output reg valid
);
  always @(*) begin
    if (request[15]) begin
      priority = 4'hF;
      valid = 1'b1;
    end else if (request[14]) begin
      priority = 4'hE;
      valid = 1'b1;
    end else if (request[0]) begin
      priority = 4'h0;
      valid = 1'b1;
    end else begin
      valid = 1'b0;
    end
  end
endmodule
